    &lt;a href=&quot;/images/xUf3QJHA2x-685.webp&quot; class=&quot;lightbox-link&quot; aria-haspopup=&quot;dialog&quot; style=&quot;cursor:zoom-in&quot;&gt;
      &lt;img class=&quot;img-lightbox&quot; alt=&quot;Boat targeted in international waters&quot; loading=&quot;lazy&quot; decoding=&quot;async&quot; style=&quot;--img-width:200&quot; src=&quot;/images/xUf3QJHA2x-200.webp&quot; width=&quot;685&quot; height=&quot;434&quot; srcset=&quot;/images/xUf3QJHA2x-200.webp 200w, /images/xUf3QJHA2x-685.webp 685w&quot; sizes=&quot;200px&quot;&gt;
