      &lt;img class=&quot;img-lightbox&quot; alt=&quot;Chicken TACO Trump&quot; loading=&quot;lazy&quot; decoding=&quot;async&quot; style=&quot;--img-width:200&quot; src=&quot;/images/HAJW06ILOD-200.webp&quot; width=&quot;800&quot; height=&quot;1069&quot; srcset=&quot;/images/HAJW06ILOD-200.webp 200w, /images/HAJW06ILOD-800.webp 800w&quot; sizes=&quot;200px&quot;&gt;
