&lt;section class=&quot;block the-ugly&quot;&gt;
    &lt;h4&gt;The ugly...&lt;/h4&gt;
    &lt;div class=&quot;blob&quot;&gt;
        &lt;div class=&quot;blob-title&quot;&gt;
            United States kills hundreds of children at Iranian elementary school &lt;a href=&quot;https://www.newsweek.com/who-bombed-the-iranian-school-11637112&quot; target=&quot;_blank&quot;&gt;[Link&lt;span class=&quot;bi bi-link-45deg&quot;&gt;&lt;/span&gt;]&lt;/a&gt;
        &lt;/div&gt;
        &lt;div class=&quot;blob-content&quot;&gt;
            &lt;div class=&quot;image-right&quot; style=&quot;width:225px&quot;&gt;

