				&lt;li&gt;&lt;a href=&quot;https://www.newsweek.com/us-military-shot-down-party-balloon-el-paso-drone-reports-11506981&quot; target=&quot;_blank&quot;&gt;(Newsweek) US military shot down party balloon after assessing as drone: Reports&lt;/a&gt;&lt;/li&gt;
            &lt;/ul&gt;
        &lt;/div&gt;
    &lt;/div&gt;
